def env_bool(name: str, default: bool = False) -> bool:
    value = os.getenv(name)
    if value is None:
        return default
    return value.strip().lower() in {"1", "true", "yes", "on"}


def env_int(name: str, default: int) -> int:
    value = os.getenv(name)
    if value is None:
        return default
    return int(value)


def parse_startup_nodes(value: str) -> List[Dict[str, Any]]:
    nodes = []
    for item in value.split(","):
        item = item.strip()
        if not item:
            continue
        if ":" not in item:
            raise ValueError(f"Invalid REDIS_STARTUP_NODES entry: {item}")
        host, port = item.rsplit(":", 1)
        nodes.append({"host": host.strip(), "port": int(port.strip())})
    if not nodes:
        raise ValueError("No valid REDIS_STARTUP_NODES provided")
    return nodes


class RedisCacheService:
    def __init__(self) -> None:
        startup_nodes = parse_startup_nodes(
            os.getenv("REDIS_STARTUP_NODES", "127.0.0.1:6379")
        )
        self.default_ttl = env_int("DEFAULT_TTL_SECONDS", 900)
        self.session_ttl = env_int("SESSION_TOKEN_TTL_SECONDS", 1800)
        self.api_key_ttl = env_int("API_KEY_TTL_SECONDS", 86400)

        self.client = RedisCluster(
            startup_nodes=startup_nodes,
            username=os.getenv("REDIS_USERNAME"),
            password=os.getenv("REDIS_PASSWORD"),
            ssl=env_bool("REDIS_SSL", False),
            ssl_cert_reqs=os.getenv("REDIS_SSL_CERT_REQS", "required"),
            decode_responses=True,
            socket_timeout=float(os.getenv("REDIS_SOCKET_TIMEOUT", "5")),
            socket_connect_timeout=float(os.getenv("REDIS_CONNECT_TIMEOUT", "5")),
            health_check_interval=env_int("REDIS_HEALTH_CHECK_INTERVAL", 30),
            retry_on_timeout=env_bool("REDIS_RETRY_ON_TIMEOUT", True),
        )

    def ping(self) -> bool:
        return bool(self.client.ping())

    def set_value(self, key: str, value: Any, ttl: Optional[int] = None) -> bool:
        ttl_value = ttl if ttl is not None else self.default_ttl
        payload = json.dumps(value, separators=(",", ":"))
        return bool(self.client.set(name=key, value=payload, ex=ttl_value))

    def get_value(self, key: str) -> Optional[Any]:
        value = self.client.get(key)
        if value is None:
            return None
        try:
            return json.loads(value)
        except json.JSONDecodeError:
            return value

    def delete_value(self, key: str) -> int:
        return int(self.client.delete(key))

    def ttl(self, key: str) -> int:
        return int(self.client.ttl(key))

    def store_session_token(self, user_id: str, token: str, ttl: Optional[int] = None) -> bool:
        key = f"session:{user_id}"
        effective_ttl = ttl if ttl is not None else self.session_ttl
        value = {
            "token": token,
            "type": "session_token",
            "stored_at": int(time.time()),
        }
        return self.set_value(key, value, effective_ttl)

    def store_api_key(self, service_id: str, api_key: str, ttl: Optional[int] = None) -> bool:
        key = f"apikey:{service_id}"
        effective_ttl = ttl if ttl is not None else self.api_key_ttl
        value = {
            "api_key": api_key,
            "type": "api_key",
            "stored_at": int(time.time()),
        }
